module	ICAP_SPARTAN6(CLK, CE, WRITE, I, O, BUSY);
	input			CLK, CE, WRITE;
	input		[15:0]	I;
	output	wire	[15:0]	O;
	output	wire	BUSY;
	reg	[15:0]	last_data;
	initial	last_data = 16'h0000;
	always @(posedge CLK)
		if ((CE)&&(WRITE))
			last_data <= I;
	assign	O = last_data;
	assign	BUSY = 1'b0;
endmodule
